create or replace function public.refresh_commission_preview_after_adjustment() returns trigger language plpgsql security definer set search_path to 'public' as $function$ declare target_month date; target_store_id uuid; begin target_month = coalesce(new.month, old.month); target_store_id = coalesce(new.store_id, old.store_id); perform public.refresh_commission_preview(target_month, target_store_id); if tg_op = 'DELETE' then return old; end if; return new; end; $function$; drop trigger if exists adjustments_refresh_commission_preview on public.adjustments; create trigger adjustments_refresh_commission_preview after insert or update or delete on public.adjustments for each row execute function public.refresh_commission_preview_after_adjustment();